 1→import { useMemo } from 'react';
 2→import { fuzzyScore } from '../../utils/fuzzy_search';
 3→import './highlighted_text.scss';
 4→
 5→interface HighlightedTextProps {
 6→  text: string;
 7→  query: string;
 8→  className?: string;
 9→}
10→
11→export function HighlightedText({
12→  text,
13→  query,
14→  className,
15→}: HighlightedTextProps) {
16→  const segments = useMemo(() => {
17→    if (!query) return null;
18→    const result = fuzzyScore(query, text);
19→    if (!result || result.indices.length === 0) return null;
20→
21→    const indexSet = new Set(result.indices);
22→    const parts: {
23→      text: string;
24→      highlighted: boolean;
25→    }[] = [];
26→    let current = '';
27→    let currentHighlighted = false;
28→
29→    for (let i = 0; i < text.length; i++) {
30→      const isHighlighted = indexSet.has(i);
31→      if (i === 0) {
32→        currentHighlighted = isHighlighted;
33→        current = text[i]!;
34→      } else if (isHighlighted === currentHighlighted) {
35→        current += text[i]!;
36→      } else {
37→        parts.push({
38→          text: current,
39→          highlighted: currentHighlighted,
40→        });
41→        current = text[i]!;
42→        currentHighlighted = isHighlighted;
43→      }
44→    }
45→    if (current) {
46→      parts.push({
47→        text: current,
48→        highlighted: currentHighlighted,
49→      });
50→    }
51→
52→    return parts;
53→  }, [
54→    text,
55→    query,
56→  ]);
57→
58→  if (!segments) {
59→    return <span className={className}>{text}</span>;
60→  }
61→
62→  return (
63→    <span className={className}>
64→      {segments.map((segment, i) =>
65→        segment.highlighted ? (
66→          <mark key={i} className="highlighted-text__match">
67→            {segment.text}
68→          </mark>
69→        ) : (
70→          <span key={i}>{segment.text}</span>
71→        ))}
72→    </span>
73→  );
74→}
