  1→import type { ListItemData, SectionData } from '../types';
  2→import { fuzzyScore } from '../utils/fuzzy_search';
  3→import type { CommandRegistration } from './types';
  4→
  5→const commands = new Map<string, CommandRegistration>();
  6→
  7→const sectionOrder: string[] = [];
  8→
  9→export function registerCommand(cmd: CommandRegistration): void {
 10→  commands.set(cmd.id, cmd);
 11→  if (!sectionOrder.includes(cmd.section)) {
 12→    sectionOrder.push(cmd.section);
 13→  }
 14→}
 15→
 16→export function getCommand(id: string): CommandRegistration | undefined {
 17→  return commands.get(id);
 18→}
 19→
 20→function toListItem(cmd: CommandRegistration): ListItemData {
 21→  return {
 22→    id: cmd.id,
 23→    title: cmd.name,
 24→    subtitle: cmd.subtitle,
 25→    icon: cmd.icon,
 26→    accessories: cmd.accessories,
 27→    detail: cmd.detail,
 28→  };
 29→}
 30→
 31→export function getSections(): SectionData[] {
 32→  const grouped = new Map<string, ListItemData[]>();
 33→
 34→  for (const section of sectionOrder) {
 35→    grouped.set(section, []);
 36→  }
 37→
 38→  for (const cmd of commands.values()) {
 39→    let items = grouped.get(cmd.section);
 40→    if (!items) {
 41→      items = [];
 42→      grouped.set(cmd.section, items);
 43→    }
 44→    items.push(toListItem(cmd));
 45→  }
 46→
 47→  const sections: SectionData[] = [];
 48→  for (const [title, items] of grouped) {
 49→    if (items.length > 0) {
 50→      sections.push({
 51→        title,
 52→        items,
 53→      });
 54→    }
 55→  }
 56→  return sections;
 57→}
 58→
 59→interface ScoredItem {
 60→  item: ListItemData;
 61→  score: number;
 62→  section: string;
 63→}
 64→
 65→function scoreItem(item: ListItemData, query: string): number {
 66→  const cmd = commands.get(item.id);
 67→  const candidates: string[] = [item.title];
 68→  if (item.subtitle) candidates.push(item.subtitle);
 69→  if (cmd?.keywords) candidates.push(...cmd.keywords);
 70→  if (cmd?.aliases) candidates.push(...cmd.aliases);
 71→
 72→  let best = -Infinity;
 73→  for (const text of candidates) {
 74→    const result = fuzzyScore(query, text);
 75→    if (result && result.score > best) {
 76→      best = result.score;
 77→    }
 78→  }
 79→  return best;
 80→}
 81→
 82→export function searchCommands(query: string): SectionData[] {
 83→  if (!query) return getSections();
 84→
 85→  const sections = getSections();
 86→  const scored: ScoredItem[] = [];
 87→
 88→  for (const section of sections) {
 89→    for (const item of section.items) {
 90→      const s = scoreItem(item, query);
 91→      if (s > -Infinity) {
 92→        scored.push({
 93→          item,
 94→          score: s,
 95→          section: section.title,
 96→        });
 97→      }
 98→    }
 99→  }
100→
101→  scored.sort((a, b) => b.score - a.score);
102→
103→  const sectionMap = new Map<string, ListItemData[]>();
104→  for (const { item, section } of scored) {
105→    let items = sectionMap.get(section);
106→    if (!items) {
107→      items = [];
108→      sectionMap.set(section, items);
109→    }
110→    items.push(item);
111→  }
112→
113→  const result: SectionData[] = [];
114→  for (const section of sections) {
115→    const items = sectionMap.get(section.title);
116→    if (items && items.length > 0) {
117→      result.push({
118→        title: section.title,
119→        items,
120→      });
121→    }
122→  }
123→  return result;
124→}
