 21→function AccessoryWrapper({
 22→  tooltip,
 23→  children,
 24→}: {
 25→  tooltip?: string;
 26→  children: ReactNode;
 27→}) {
 28→  if (tooltip) {
 29→    return <Tooltip content={tooltip}>{children}</Tooltip>;
