 33→
 34→export function ListItem({
 35→  index,
 36→  icon,
 37→  title,
 38→  subtitle,
 39→  accessories,
 40→  onClick,
 41→  query,
 42→}: ListItemProps) {
 43→  const { activeIndex, setActiveIndex } = useListContext();
 44→  const isActive = activeIndex === index;
 45→  const now = useMemo(() => new Date(), []);
 46→
 47→  const handleMouseEnter = useCallback(() => {
 48→    setActiveIndex(index);
 49→  }, [
 50→    index,
 51→    setActiveIndex,
 52→  ]);
 53→
 54→  return (
 55→    <div
 56→      id={`list-item-${index}`}
 57→      className={`list-item${isActive ? ' list-item--active' : ''}`}
 58→      data-list-index={index}
 59→      role="option"
 60→      aria-selected={isActive}
 61→      onMouseEnter={handleMouseEnter}
 62→      onClick={onClick}
 63→    >
 64→      <div className="list-item__left">
 65→        {icon && <span className="list-item__icon">{icon}</span>}
 66→        {query ? (
 67→          <HighlightedText
 68→            text={title}
 69→            query={query}
 70→            className="list-item__title"
 71→          />
 72→        ) : (
 73→          <span className="list-item__title">{title}</span>
 74→        )}
 75→        {subtitle &&
 76→          (query ? (
 77→            <HighlightedText
 78→              text={subtitle}
 79→              query={query}
 80→              className="list-item__subtitle"
 81→            />
 82→          ) : (
 83→            <span className="list-item__subtitle">{subtitle}</span>
 84→          ))}
 85→      </div>
 86→      {accessories && accessories.length > 0 && (
 87→        <div className="list-item__accessories">
 88→          {accessories.map((accessory, i) => {
 89→            const tooltipText =
 90→              accessory.tooltip ??
 91→              (accessory.date ? accessory.date.toLocaleString() : undefined);
 92→
 93→            if (accessory.tag) {
 94→              const hex = accessory.tag.color
 95→                ? TAG_COLOR_HEX[accessory.tag.color]
 96→                : undefined;
 97→              return (
 98→                <AccessoryWrapper key={i} tooltip={tooltipText}>
 99→                  <span
100→                    className="list-item__accessory-tag"
101→                    style={
102→                      hex
103→                        ? {
104→                            color: hex,
105→                            backgroundColor: `${hex}26`,
106→                          }
107→                        : undefined
108→                    }
109→                  >
110→                    {accessory.tag.text}
111→                  </span>
112→                </AccessoryWrapper>
113→              );
114→            }
115→            const displayText = accessory.date
116→              ? formatRelativeDate(accessory.date, now)
117→              : accessory.text;
118→
119→            return (
120→              <AccessoryWrapper key={i} tooltip={tooltipText}>
121→                <span className="list-item__accessory">
122→                  {accessory.icon}
123→                  {displayText && (
124→                    <span className="list-item__accessory-text">
125→                      {displayText}
126→                    </span>
127→                  )}
128→                </span>
129→              </AccessoryWrapper>
130→            );
131→          })}
132→        </div>
133→      )}
134→    </div>
135→  );
136→}
