136→const PIN_STATE_KEY = 'clipboard-pins';
137→const DELETED_KEY = 'clipboard-deleted';
138→
139→function loadInitialEntries(): ClipboardEntry[] {
140→  const pinState = storageGet(PIN_STATE_KEY, isBooleanRecord) ?? {};
141→  const deleted = new Set(storageGet(DELETED_KEY, isStringArray) ?? []);
142→  return MOCK_CLIPBOARD_ENTRIES.filter(e => !deleted.has(e.id)).map(e => ({
143→    ...e,
144→    pinned: e.id in pinState ? pinState[e.id]! : e.pinned,
145→  }));
146→}
147→
148→function saveEntryState(entries: ClipboardEntry[]) {
149→  const pinState: Record<string, boolean> = {};
150→  for (const e of entries) {
151→    pinState[e.id] = e.pinned;
152→  }
153→  storageSet(PIN_STATE_KEY, pinState);
154→
155→  const allIds = new Set(MOCK_CLIPBOARD_ENTRIES.map(e => e.id));
156→  const currentIds = new Set(entries.map(e => e.id));
157→  const deleted = [...allIds].filter(id => !currentIds.has(id));
158→  storageSet(DELETED_KEY, deleted);
159→}
