 91→function truncateContent(content: string, maxLength: number): string {
 92→  const singleLine = content.replace(/\n/g, ' ');
 93→  if (singleLine.length <= maxLength) return singleLine;
 94→  return singleLine.slice(0, maxLength) + '\u2026';
 95→}
