 59→function loadRecentEmojis(): string[] {
 60→  const stored = storageGet(STORAGE_KEY, isStringArray);
 61→  if (stored) return stored;
 62→
 63→  try {
 64→    const legacy = localStorage.getItem('emoji-picker-recent');
 65→    if (legacy) {
 66→      const parsed: unknown = JSON.parse(legacy);
 67→      if (isStringArray(parsed)) {
 68→        storageSet(STORAGE_KEY, parsed);
 69→        localStorage.removeItem('emoji-picker-recent');
 70→        return parsed;
 71→      }
 72→    }
 73→  } catch {
 74→    // unavailable
 75→  }
 76→  return [];
 77→}
