 841→
 842→  const activeDescendantId =
 843→    isRoot && allItems.length > 0 ? `list-item-${selectedIndex}` : undefined;
 844→
 845→  const navDirectionClass =
 846→    nav.direction === 'push'
 847→      ? ' command-palette__nav-view--push'
 848→      : nav.direction === 'pop'
 849→        ? ' command-palette__nav-view--pop'
 850→        : '';
 851→
 852→  const contextLabel =
 853→    nav.breadcrumbs.length > 0
 854→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
 855→      : 'Raycast';
 856→
 857→  function renderCurrentView() {
 858→    const entry = nav.currentEntry;
 859→    if (!entry) return null;
 860→
 861→    if (entry.data.type === 'command') {
 862→      const cmd = getCommand(entry.data.commandId);
 863→      if (cmd?.component) {
 864→        const Component = cmd.component;
 865→        return <Component />;
 866→      }
 867→      return null;
 868→    }
 869→
 870→    if (entry.data.type === 'detail') {
 871→      return <DetailView item={entry.data.item} />;
 872→    }
 873→
 874→    return null;
 875→  }
